  69→const PRIVATE_NO_STORE_CACHE_CONTROL = 'private, no-store';
  70→const METRICS_TOKEN = (process.env.METRICS_TOKEN || '').trim();
  71→const METRICS_ROUTE_LIMIT = 200;
  72→const CACHEABLE_PUBLIC_ROUTE_PATTERNS = [
