 100→const normalizeApiPath = (path = '') => (
 101→    String(path).startsWith('/api/')
 102→        ? String(path).slice(4)
 103→        : String(path)
 104→);
 105→
 106→const canonicalizeMetricsPath = (rawPath = '') => {
 107→    const normalized = normalizeApiPath(rawPath);
 108→    return normalized
 109→        .replace(/\/[0-9a-f]{8}-[0-9a-f-]{27,}(?=\/|$)/ig, '/:id')
 110→        .replace(/\/\d+(?=\/|$)/g, '/:id');
 111→};
