 113→const isPersonalizedGetRequest = (req) => {
 114→    if (req?.headers?.authorization) {
 115→        return true;
 116→    }
 117→
 118→    const userId = String(req?.query?.userId || '').trim();
 119→    const loggedInUserId = String(req?.query?.loggedInUserId || '').trim();
 120→    return Boolean(userId || loggedInUserId);
 121→};
 122→
 123→const isCacheablePublicPath = (reqPath = '') => (
 124→    CACHEABLE_PUBLIC_ROUTE_PATTERNS.some((pattern) => pattern.test(reqPath))
 125→);
