 209→const extractFromLexical = (contentJson) => {
 210→    try {
 211→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 212→        const texts = [];
 213→        let firstImage = null;
 214→
 215→        const walk = (node) => {
 216→            if (!node || typeof node !== 'object') return;
 217→
 218→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 219→            if (nodeType === 'text' && typeof node.text === 'string') {
 220→                texts.push(node.text);
 221→            }
 222→
 223→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 224→            if (!firstImage && isImageNode) {
 225→                const image = imageFromNodeLike(node);
 226→                if (image) {
 227→                    firstImage = image;
 228→                }
 229→            }
 230→
 231→            if (Array.isArray(node.children)) {
 232→                node.children.forEach(walk);
 233→            }
 234→        };
 235→
 236→        if (parsed?.root) {
 237→            walk(parsed.root);
 238→        }
 239→
 240→        return {
 241→            text: normalizeWhitespace(texts.join(' ')),
 242→            image: firstImage
 243→        };
 244→    } catch {
 245→        return { text: '', image: null };
 246→    }
 247→};
 248→
 249→const extractFromCanvasDoc = (canvasDocRaw) => {
 250→    try {
 251→        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
 252→        const text = Array.isArray(doc?.snippets)
 253→            ? normalizeWhitespace(
 254→                doc.snippets
 255→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
 256→                    .join(' ')
 257→            )
 258→            : '';
 259→
 260→        let image = null;
 261→        if (Array.isArray(doc?.images)) {
 262→            const first = doc.images.find((img) => imageFromNodeLike(img));
 263→            if (first) image = imageFromNodeLike(first);
 264→        }
 265→
 266→        return { text, image };
 267→    } catch {
 268→        return { text: '', image: null };
 269→    }
 270→};
