 272→const buildShareMetaFromJournal = (journal) => {
 273→    const lexicalData = extractFromLexical(journal?.content);
 274→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
 275→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
 276→    const title = normalizedTitle || 'Untitled Post';
 277→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
 278→
 279→    let description = lexicalData.text || '';
 280→    if (!description && canvasData.text) {
 281→        description = canvasData.text;
 282→    }
 283→    if (!description) {
 284→        description = `Read "${title}" by ${authorName} on Iskryb`;
 285→    }
 286→
 287→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
 288→    let imageCandidateSource = 'fallback';
 289→    if (lexicalData.image?.src) {
 290→        imageCandidate = lexicalData.image.src;
