 309→const resolveAbsoluteHttpUrl = (rawUrl) => {
 310→    try {
 311→        const raw = String(rawUrl || '').trim();
 312→        if (!raw) return null;
 313→
 314→        const isSupabasePath =
 315→            raw.startsWith('/storage/v1/object/public/')
 316→            || raw.startsWith('storage/v1/object/public/');
 317→
 318→        const baseUrl = isSupabasePath && SUPABASE_URL
 319→            ? `${SUPABASE_URL}/`
 320→            : SITE_URL;
 321→
 322→        const parsed = new URL(raw, baseUrl);
 323→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 324→            return null;
 325→        }
 326→        return parsed.toString();
 327→    } catch {
 328→        return null;
 329→    }
 330→};
