 332→const isPrivateIpv4Address = (ip) => {
 333→    const parts = ip.split('.').map((part) => Number(part));
 334→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 335→        return true;
 336→    }
 337→
 338→    const [a, b] = parts;
 339→    if (a === 10 || a === 127 || a === 0) return true;
 340→    if (a === 169 && b === 254) return true;
 341→    if (a === 172 && b >= 16 && b <= 31) return true;
 342→    if (a === 192 && b === 168) return true;
 343→    return false;
 344→};
 345→
 346→const isPrivateIpv6Address = (ip) => {
 347→    const normalized = ip.toLowerCase();
 348→    return (
 349→        normalized === '::1' ||
 350→        normalized.startsWith('fc') ||
 351→        normalized.startsWith('fd') ||
 352→        normalized.startsWith('fe80:')
 353→    );
 354→};
 355→
 356→const isPrivateIpAddress = (ip) => {
 357→    const ipVersion = net.isIP(ip);
 358→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
 359→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
 360→    return true;
 361→};
