 385→const evaluateShareImageCandidate = (rawUrl) => {
 386→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
 387→    if (!absoluteUrl) {
 388→        return {
 389→            ok: false,
 390→            reason: 'invalid_or_non_http_url',
 391→            resolvedUrl: null,
 392→        };
 393→    }
 394→
 395→    let path = '';
 396→    try {
 397→        const parsed = new URL(absoluteUrl);
 398→        path = String(parsed.pathname || '').toLowerCase();
 399→    } catch {
 400→        return {
 401→            ok: false,
 402→            reason: 'invalid_resolved_url',
 403→            resolvedUrl: null,
 404→        };
 405→    }
 406→
 407→    if (path.endsWith('.svg')) {
 408→        return {
 409→            ok: false,
 410→            reason: 'svg_not_supported_for_share_image',
 411→            resolvedUrl: absoluteUrl,
 412→        };
 413→    }
 414→
 415→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 416→        return {
 417→            ok: false,
 418→            reason: 'unsafe_remote_url',
 419→            resolvedUrl: absoluteUrl,
 420→        };
 421→    }
 422→
 423→    return {
 424→        ok: true,
 425→        reason: 'ok',
 426→        resolvedUrl: absoluteUrl,
 427→    };
 428→};
