 489→const convertToOgJpeg = async (inputBuffer) => {
 490→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
 491→        .rotate()
 492→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
 493→            fit: 'contain',
 494→            background: { r: 255, g: 255, b: 255, alpha: 1 },
 495→        })
 496→        .jpeg({ quality: 82, mozjpeg: true })
 497→        .toBuffer();
 498→};
